const $=id=>document.getElementById(id);const cS=$("stack"),gS=cS.getContext("2d"),cF=$("fields"),gF=cF.getContext("2d"),cC=$("closure"),gC=cC.getContext("2d");let running=true,speed=1,start=performance.now(),paused=0;const layers=['Símbolo','⦙ META','Campos ⧀','Contrato ⛬','Fecho ☩'];const metricNames=['Pressao','Intensao','Consumo','Universal','Tempo'];function initUI(){$('metrics').innerHTML=metricNames.map((m,i)=>`<div class="metric"><b>${m}</b><span id="mval-${i}">0.00</span><i id="mfill-${i}" style="width:20%"></i></div>`).join('')}function fit(c){const d=window.devicePixelRatio||1,r=c.getBoundingClientRect();c.width=Math.max(1,r.width*d);c.height=Math.max(1,r.height*d);c.getContext('2d').setTransform(d,0,0,d,0,0)}function resize(){fit(cS);fit(cF);fit(cC)}function clamp(v,a,b){return Math.max(a,Math.min(b,v))}function compute(t){const phase=(Math.sin(t*.8)+1)/2;return{phase,layer:Math.floor((t*.7)%5)}}function drawStack(t,s){const w=cS.width/(window.devicePixelRatio||1),h=cS.height/(window.devicePixelRatio||1);gS.clearRect(0,0,w,h);const bh=56,startY=40;for(let i=0;i<5;i++){const y=startY+i*bh;const active=i===s.layer;gS.fillStyle=active?'rgba(255,214,74,.15)':'rgba(255,255,255,.03)';gS.strokeStyle=active?'rgba(255,214,74,.9)':'rgba(220,232,248,.14)';gS.fillRect(120,y,260,44);gS.strokeRect(120,y,260,44);gS.fillStyle='rgba(236,244,255,.9)';gS.font='16px Segoe UI';gS.fillText(layers[i],150,y+28)}$('layerNow').textContent=layers[s.layer];$('stackInfo').textContent=layers[s.layer];$('closureInfo').textContent=`fecho ${s.phase.toFixed(2)}`}function drawFields(t,s){const w=cF.width/(window.devicePixelRatio||1),h=cF.height/(window.devicePixelRatio||1);gF.clearRect(0,0,w,h);for(let i=0;i<4;i++){const y=30+i*32;const v=(Math.sin(t+i*.7)+1)/2;gF.fillStyle='rgba(255,255,255,.05)';gF.fillRect(30,y,w-60,16);gF.fillStyle='rgba(79,224,138,.7)';gF.fillRect(30,y,(w-60)*v,16)}$('fieldInfo').textContent='Campos ⧀';$('contractInfo').textContent='Contrato ⛬'}function drawClosure(t,s){const w=cC.width/(window.devicePixelRatio||1),h=cC.height/(window.devicePixelRatio||1);gC.clearRect(0,0,w,h);const cx=w/2,cy=h/2;for(let i=0;i<5;i++){gC.strokeStyle=`rgba(79,224,138,${.08+i*.08})`;gC.beginPath();gC.arc(cx,cy,20+i*14,0,Math.PI*2);gC.stroke()}gC.fillStyle='#ffd64a';gC.font='bold 42px Segoe UI';gC.fillText('☩',cx-16,cy+14);$('sealInfo').textContent='☩';$('integrityInfo').textContent=`integridade ${(1-s.phase*.2).toFixed(2)}`;$('stateNow').textContent=s.layer===4?'SEALED':'OPEN'}function updateMetrics(t,p){const vals=[.42+.18*Math.sin(t*.8)+p*.18,.46+.21*Math.sin(t*.7+1),.32+.34*(1-p),.58+.12*Math.sin(t*.35),(t%60)/60];vals.forEach((v,i)=>{const vv=clamp(v,0,1);document.getElementById('mfill-'+i).style.width=`${vv*100}%`;$('mval-'+i).textContent=i===4?$('timeNow').textContent:vv.toFixed(2)})}function loop(now){const t=running?(now-start)/1000*speed:paused;$('timeNow').textContent=`${String(Math.floor(t/60)).padStart(2,'0')}:${String(Math.floor(t%60)).padStart(2,'0')}`;const s=compute(t);drawStack(t,s);drawFields(t,s);drawClosure(t,s);updateMetrics(t,s.phase);requestAnimationFrame(loop)}$('toggle').onclick=()=>{running=!running;if(running){start=performance.now()-paused*1000/speed;$('toggle').textContent='Pausar'}else{paused=(performance.now()-start)/1000*speed;$('toggle').textContent='Executar'}};$('reset').onclick=()=>{start=performance.now();paused=0};$('speed').oninput=e=>{speed=Number(e.target.value);$('speedText').textContent=`${speed.toFixed(2)}x`};window.addEventListener('resize',resize);initUI();resize();requestAnimationFrame(loop);